418:     /**
419:      * Grow buffers to process next batch of records from `sourceRecords.` Buffers are doubled in size
420:      * up to a maximum of `maxLogMessageSize`. In some scenarios, a record could be bigger than the
421:      * current maximum size configured for the log. For example:
422:      * <ol>
423:      *   <li>A compacted topic using compression may contain a message set slightly larger than max.message.bytes</li>
424:      *   <li>max.message.bytes of a topic could have been reduced after writing larger messages</li>
425:      * </ol>
426:      * In these cases, grow the buffer to hold the next batch.
427:      *
428:      * @param sourceRecords The dirty log segment records to process
429:      * @param position The current position in the read buffer to read from
430:      * @param maxLogMessageSize The maximum record size in bytes for the topic
431:      * @param memoryRecords The memory records in read buffer
432:      */
433:     private void growBuffersOrFail(FileRecords sourceRecords,
434:                                    int position,
435:                                    int maxLogMessageSize,
436:                                    MemoryRecords memoryRecords) throws IOException {
437:         int maxSize;
438: 
439:         if (readBuffer.capacity() >= maxLogMessageSize) {
440:             Integer nextBatchSize = memoryRecords.firstBatchSize();
441:             String logDesc = String.format("log segment %s at position %d", sourceRecords.file(), position);
442:             if (nextBatchSize == null) {
443:                 throw new IllegalStateException("Could not determine next batch size for " + logDesc);
444:             }
445:             if (nextBatchSize <= 0) {
446:                 throw new IllegalStateException("Invalid batch size " + nextBatchSize + " for " + logDesc);
447:             }
448:             if (nextBatchSize <= readBuffer.capacity()) {
449:                 throw new IllegalStateException("Batch size " + nextBatchSize + " < buffer size " + readBuffer.capacity() + ", but not processed for " + logDesc);
450:             }
451:             long bytesLeft = sourceRecords.channel().size() - position;
452:             if (nextBatchSize > bytesLeft) {
453:                 throw new CorruptRecordException("Log segment may be corrupt, batch size " + nextBatchSize + " > " + bytesLeft + " bytes left in segment for " + logDesc);
454:             }
455: 
456:             maxSize = nextBatchSize;
457:         } else {
458:             maxSize = maxLogMessageSize;
459:         }
460: 
461:         growBuffers(maxSize);
462:     }
