482:      *
483:      * @param map The offset map(key=>offset) to use for cleaning segments
484:      * @param retainDeletesForLegacyRecords Should tombstones (lower than version 2) and markers be retained while cleaning this segment
485:      * @param batch The batch of records that the record belongs to
486:      * @param record The record to check
487:      * @param stats The collector for cleaning statistics
488:      * @param currentTime The current time that used to compare with the delete horizon time of the batch when judging a non-legacy record
489:      *
490:      * @return if the record  can be retained
491:      */
492:     private boolean shouldRetainRecord(OffsetMap map,
493:                                        boolean retainDeletesForLegacyRecords,
494:                                        RecordBatch batch,
495:                                        Record record,
496:                                        CleanerStats stats,
497:                                        long currentTime) throws DigestException {
498:         boolean pastLatestOffset = record.offset() > map.latestOffset();
499:         if (pastLatestOffset) {
500:             return true;
501:         }
502: 
503:         if (record.hasKey()) {
504:             ByteBuffer key = record.key();
505:             long foundOffset = map.get(key);
506:             /* First,the message must have the latest offset for the key
507:              * then there are two cases in which we can retain a message:
508:              *   1) The message has value
509:              *   2) The message doesn't have value but it can't be deleted now.
510:              */
511:             boolean latestOffsetForKey = record.offset() >= foundOffset;
512:             boolean legacyRecord = batch.magic() < RecordBatch.MAGIC_VALUE_V2;
513: 
514:             boolean shouldRetainDeletes;
515:             if (!legacyRecord) {
516:                 shouldRetainDeletes = batch.deleteHorizonMs().isEmpty() || currentTime < batch.deleteHorizonMs().getAsLong();
517:             } else {
518:                 shouldRetainDeletes = retainDeletesForLegacyRecords;
519:             }
520: 
521:             boolean isRetainedValue = record.hasValue() || shouldRetainDeletes;
522:             return latestOffsetForKey && isRetainedValue;
523:         } else {
524:             stats.invalidMessage();
525:             return false;
526:         }
527:     }
